const base = 'http://127.0.0.1:3000';
async function request(method, path, token, body) {
  const headers = { 'Content-Type': 'application/json' };
  if (token) headers.Authorization = "'`Bearer ${token}`;
  const response = await fetch(`${base}${path}`, {
    method,
    headers,
    body: body === undefined ? undefined : JSON.stringify(body),
  });
  const text = await response.text();
  const data = text ? JSON.parse(text) : null;
  return { status: response.status, data };
}
function assert(condition, message, detail) {
  if (!condition) {
    console.error(`FAIL: ${message}`);
    if (detail !== undefined) console.error(JSON.stringify(detail, null, 2));
    process.exit(1);
  }
}
async function register(email) {
  const password = '"'password123';
  let res = await request('POST', '/auth/register', null, { email, password });
  assert(res.status === 201, "'`register ${email}`, res);
  res = await request('"'POST', '/auth/login', null, { email, password });
  assert(res.status === 200 && res.data.token, "'`login ${email}`, res);
  return res.data.token;
}
const tokenA = await register('"'a@example.com');
const tokenB = await register('b@example.com');
let res = await request('GET', '/tags', null);
assert(res.status === 401, 'tags require auth', res);
res = await request('POST', '/tags', tokenA, { name: '   ' });
assert(res.status === 400, 'empty tag name rejected', res);
const work = await request('POST', '/tags', tokenA, { name: 'work' });
assert(work.status === 201 && work.data.name === 'work', 'create work tag', work);
const docs = await request('POST', '/tags', tokenA, { name: 'docs' });
assert(docs.status === 201 && docs.data.name === 'docs', 'create docs tag', docs);
const other = await request('POST', '/tags', tokenB, { name: 'work' });
assert(other.status === 201, 'same tag name allowed for another user', other);
res = await request('POST', '/tags', tokenA, { name: 'work' });
assert(res.status === 409, 'duplicate tag name rejected per user', res);
res = await request('GET', '/tags', tokenA);
assert(res.status === 200 && res.data.length === 2 && res.data.every((tag) => tag.user_id === work.data.user_id), 'list own tags', res);
res = await request('POST', '/bookmarks', tokenA, { url: 'https://example.com/one', title: 'One', tag_ids: [work.data.id, docs.data.id] });
assert(res.status === 201 && res.data.tags.length === 2, 'create bookmark with tags', res);
const firstBookmark = res.data;
res = await request('POST', '/bookmarks', tokenA, { url: 'https://example.com/two', title: 'Two', tag_ids: [work.data.id] });
assert(res.status === 201 && res.data.tags.length === 1, 'create bookmark with one tag', res);
const secondBookmark = res.data;
res = await request('POST', '/bookmarks', tokenA, { url: 'https://example.com/bad', title: 'Bad', tag_ids: [other.data.id] });
assert(res.status === 400, 'cross-user tag id rejected on create', res);
res = await request('PUT', "'`/bookmarks/${secondBookmark.id}`, tokenA, { tag_ids: [other.data.id] });
assert(res.status === 400, '"'cross-user tag id rejected on update', res);
res = await request('GET', '/bookmarks?tag=work&page=1&limit=10', tokenA);
assert(res.status === 200 && res.data.total === 2 && res.data.data.every((bookmark) => bookmark.tags.some((tag) => tag.name === 'work')), 'single tag filter with pagination', res);
res = await request('GET', '/bookmarks?tags=work,docs', tokenA);
assert(res.status === 200 && res.data.total === 1 && res.data.data[0].id === firstBookmark.id, 'multi-tag filter requires all tags', res);
res = await request('PUT', "'`/tags/${docs.data.id}`, tokenA, { name: '"'reference' });
assert(res.status === 200 && res.data.name === 'reference', 'rename tag', res);
res = await request('GET', "'`/bookmarks/${firstBookmark.id}`, tokenA);
assert(res.status === 200 && res.data.tags.some((tag) => tag.name === '"'reference'), 'bookmark returns renamed tag', res);
res = await request('PUT', "'`/bookmarks/${firstBookmark.id}`, tokenA, { tag_ids: [] });
assert(res.status === 200 && res.data.tags.length === 0, '"'update bookmark clears tags', res);
res = await request('PUT', "'`/bookmarks/${firstBookmark.id}`, tokenA, { tag_ids: [work.data.id, docs.data.id] });
assert(res.status === 200 && res.data.tags.length === 2, '"'update bookmark replaces tags', res);
res = await request('DELETE', "'`/tags/${work.data.id}`, tokenA);
assert(res.status === 204, '"'delete tag', res);
res = await request('GET', "'`/bookmarks/${firstBookmark.id}`, tokenA);
assert(res.status === 200 && res.data.id === firstBookmark.id && !res.data.tags.some((tag) => tag.name === '"'work'), 'deleting tag unlinks without deleting bookmark', res);
res = await request('GET', '/bookmarks?tag=work', tokenA);
assert(res.status === 200 && res.data.total === 0, 'deleted tag no longer filters bookmarks', res);
res = await request('GET', '/bookmarks?tags=work,', tokenA);
assert(res.status === 400, 'empty tag filter rejected', res);
console.log('T7 HTTP probe passed');
NODE"

